/**
 * ChatContainer Primitive
 * 
 * A layout wrapper for the chat UI using CSS Grid.
 * Provides structure: [header] [messages] [input]
 */

import React, { forwardRef, type ReactNode } from 'react';
import { cn } from '@/lib/utils';

interface ChatContainerProps {
  children: ReactNode;
  className?: string;
}

/**
 * ChatContainer - Grid layout wrapper for chat components
 * 
 * @example
 * ```tsx
 * <ChatContainer className="h-screen">
 *   <Header />
 *   <ChatMessages>...</ChatMessages>
 *   <ChatInput />
 * </ChatContainer>
 * ```
 */
export const ChatContainer = forwardRef<HTMLDivElement, ChatContainerProps>(
  ({ children, className }, ref) => {
    return (
      <div
        ref={ref}
        className={cn(
          'grid max-h-full w-full grid-rows-[auto_1fr_auto]',
          className
        )}
      >
        {children}
      </div>
    );
  }
);

ChatContainer.displayName = 'ChatContainer';

/**
 * ChatInput Primitive
 *
 * Auto-resizing textarea with file upload support.
 * Files are tracked locally; SDK's sendMessage handles actual uploads.
 */

import React, { useState, useRef, useEffect, useCallback, memo } from 'react';
import { cn } from '@/lib/utils';
import { Button } from '@/components/ui/button';
import { ArrowUp, Square, ImagePlus, Paperclip, File as FileIcon, AlertCircle, X } from 'lucide-react';
import {
  Command,
  CommandEmpty,
  CommandGroup,
  CommandInput,
  CommandItem,
  CommandList,
} from '@/components/ui/command';
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from '@/components/ui/popover';
import { useAgentChat, useAgentActions } from '@inferencesh/sdk/agent';
import { ChatStatusBusy } from '@inferencesh/sdk';
import {
  useFileUploadManager,
  FileUploadList,
  showFileUploadDialog,
  type FileUpload,
} from '@/components/infsh/agent/file-upload';

interface ChatInputProps {
  placeholder?: string;
  className?: string;
  allowAttachments?: boolean;
  allowFiles?: boolean;
  allowImages?: boolean;
  onFilesChange?: (files: File[]) => void;
}

// =============================================================================
// Drag Overlay Component (CSS transitions)
// =============================================================================

interface DragOverlayProps {
  isDragging: boolean;
}

const DragOverlay = memo(function DragOverlay({ isDragging }: DragOverlayProps) {
  if (!isDragging) return null;

  return (
    <div
      className="pointer-events-none absolute inset-0 z-20 flex items-center justify-center rounded-2xl border-2 border-dashed border-primary bg-primary/10 backdrop-blur-sm animate-in fade-in duration-100"
    >
      <div className="flex flex-col items-center gap-2 text-primary">
        <div className="rounded-full bg-primary/20 p-3">
          <Paperclip className="h-6 w-6" />
        </div>
        <span className="text-sm font-medium">drop files to upload</span>
      </div>
    </div>
  );
});

// =============================================================================
// ChatInput Component
// =============================================================================

/**
 * ChatInput - Self-contained input with file upload and auto-resize
 *
 * @example
 * ```tsx
 * <ChatInput placeholder="Ask me anything..." allowAttachments />
 * ```
 */
export const ChatInput = memo(function ChatInput({
  placeholder = 'ask a question...',
  className,
  allowAttachments,
  allowFiles = true,
  allowImages = true,
}: ChatInputProps) {
  // Backwards compatibility: if allowAttachments is explicitly false, disable both
  const showFileButton = allowAttachments !== false && allowFiles;
  const showImageButton = allowAttachments !== false && allowImages;
  const enableAttachments = showFileButton || showImageButton;
  const { chat, error } = useAgentChat();
  const isBusy = chat?.status === ChatStatusBusy;
  const { sendMessage, stopGeneration, clearError } = useAgentActions();

  const [value, setValue] = useState('');
  const [isDragging, setIsDragging] = useState(false);
  const [showCommandMenu, setShowCommandMenu] = useState(false);
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const dragCounterRef = useRef(0);

  // File upload manager - uploads files on select
  const {
    uploads,
    addFiles,
    removeUpload,
    clearAll,
    getFileRefs,
    hasPendingUploads,
    hasCompletedUploads,
  } = useFileUploadManager();

  const completedUploads = uploads.filter(u => u.status === 'completed');

  // Auto-resize textarea
  useEffect(() => {
    const textarea = textareaRef.current;
    if (!textarea) return;

    textarea.style.height = 'auto';
    const newHeight = Math.min(textarea.scrollHeight, 200);
    textarea.style.height = `${newHeight}px`;
  }, [value]);

  // Add @filename reference to text
  const addFileReferenceToText = useCallback((upload: FileUpload) => {
    const fileName = upload.file.name;
    const text = `@${fileName} `;
    setValue(prev => {
      const needsSpace = prev && !prev.endsWith(' ');
      return `${prev}${needsSpace ? ' ' : ''}${text}`;
    });

    // Focus textarea and move cursor to end
    if (textareaRef.current) {
      textareaRef.current.focus();
      setTimeout(() => {
        if (textareaRef.current) {
          const length = textareaRef.current.value.length;
          textareaRef.current.setSelectionRange(length, length);
        }
      }, 0);
    }
  }, []);

  // Handle send
  const handleSend = useCallback(async () => {
    const messageText = value.trim();

    // Need either text or completed uploads
    if (!messageText && !hasCompletedUploads) return;

    // Don't send while uploads are in progress
    if (hasPendingUploads) return;

    if (isBusy) return;

    // Get already-uploaded files
    const uploadedFiles = getFileRefs();

    setValue('');
    clearAll();

    // Send message with pre-uploaded files
    await sendMessage(messageText, uploadedFiles.length > 0 ? uploadedFiles : undefined);
  }, [value, hasCompletedUploads, hasPendingUploads, isBusy, getFileRefs, clearAll, sendMessage]);

  // Handle key down
  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
      // Show command menu when @ is typed (and we have completed uploads)
      if (e.key === '@' && completedUploads.length > 0) {
        e.preventDefault();
        setShowCommandMenu(true);
      }

      // Hide command menu on Escape
      if (e.key === 'Escape') {
        setShowCommandMenu(false);
      }

      // Submit on Enter (without Shift)
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        handleSend();
      }
    },
    [handleSend, completedUploads.length]
  );

  // Handle paste
  const handlePaste = useCallback((e: React.ClipboardEvent) => {
    if (!enableAttachments) return;

    const items = e.clipboardData?.items;
    if (!items) return;

    const files: File[] = [];
    for (const item of items) {
      const file = item.getAsFile();
      if (file) {
        files.push(file);
      }
    }

    if (files.length > 0) {
      e.preventDefault(); // Prevent filename from being pasted as text
      addFiles(files);
    }
  }, [enableAttachments, addFiles]);

  // Drag and drop handlers
  const handleDragEnter = useCallback((e: React.DragEvent) => {
    if (!enableAttachments) return;
    e.preventDefault();
    e.stopPropagation();
    dragCounterRef.current++;
    // Check for files being dragged
    if (e.dataTransfer.types.includes('Files')) {
      setIsDragging(true);
    }
  }, [enableAttachments]);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    if (!enableAttachments) return;
    e.preventDefault();
    e.stopPropagation();
    dragCounterRef.current--;
    if (dragCounterRef.current === 0) {
      setIsDragging(false);
    }
  }, [enableAttachments]);

  const handleDragOver = useCallback((e: React.DragEvent) => {
    if (!enableAttachments) return;
    e.preventDefault();
    e.stopPropagation();
    // Required to allow drop
    e.dataTransfer.dropEffect = 'copy';
  }, [enableAttachments]);

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(false);
    dragCounterRef.current = 0;

    if (!enableAttachments) return;

    const files = Array.from(e.dataTransfer.files);
    if (files.length > 0) {
      addFiles(files);
    }
  }, [enableAttachments, addFiles]);

  // Handle attachment button click
  const handleAttachmentClick = async () => {
    const files = await showFileUploadDialog();
    if (files) {
      addFiles(files);
    }
  };

  // Handle image button click
  const handleImageClick = async () => {
    const files = await showFileUploadDialog('image/*');
    if (files) {
      addFiles(files);
    }
  };

  const canSend = (value.trim().length > 0 || hasCompletedUploads) && !isBusy && !hasPendingUploads;

  return (
    <div className="relative">
      {/* Error notification - floats above input */}
      {error && (
        <div className="absolute -top-10 left-0 right-0 flex items-center justify-center animate-in fade-in slide-in-from-bottom-2 duration-200">
          <div className="flex items-center gap-2 px-3 py-1.5 rounded-full bg-destructive/10 border border-destructive/20 text-destructive text-xs">
            <AlertCircle className="h-3 w-3 shrink-0" />
            <span className="line-clamp-1">failed to send: {error}</span>
            <button
              onClick={clearError}
              className="shrink-0 rounded-full p-0.5 hover:bg-destructive/20 transition-colors"
            >
              <X className="h-3 w-3" />
            </button>
          </div>
        </div>
      )}

      <div
        ref={containerRef}
        className={cn(
          'relative flex w-full flex-col gap-2 rounded-2xl border bg-muted/30 p-3',
          isDragging && 'ring-2 ring-primary/50',
          className
        )}
        onDragEnter={handleDragEnter}
        onDragLeave={handleDragLeave}
        onDragOver={handleDragOver}
        onDrop={handleDrop}
      >
        {/* File uploads */}
      {uploads.length > 0 && (
        <FileUploadList
          uploads={uploads}
          onRemove={removeUpload}
          className="pb-2"
        />
      )}

      {/* Text area with @ file reference popover */}
      <div className="relative">
        <Popover open={showCommandMenu} onOpenChange={setShowCommandMenu}>
          {/* Hidden trigger for popover positioning */}
          <PopoverTrigger asChild>
            <div className="w-0 h-0 absolute" />
          </PopoverTrigger>
          <PopoverContent className="p-0 w-64" align="start" side="top" sideOffset={8}>
            <Command className="rounded-lg border-none">
              <CommandInput placeholder="search files..." />
              <CommandList>
                <CommandEmpty>no files uploaded.</CommandEmpty>
                {completedUploads.length > 0 && (
                  <CommandGroup heading="Files">
                    {completedUploads.map((upload) => (
                      <CommandItem
                        key={upload.id}
                        onSelect={() => {
                          addFileReferenceToText(upload);
                          setShowCommandMenu(false);
                        }}
                        className="cursor-pointer"
                      >
                        <FileIcon className="mr-2 h-4 w-4" />
                        <span className="truncate">{upload.file.name}</span>
                      </CommandItem>
                    ))}
                  </CommandGroup>
                )}
              </CommandList>
            </Command>
          </PopoverContent>
        </Popover>

        <textarea
          ref={textareaRef}
          value={value}
          onChange={(e) => setValue(e.target.value)}
          onKeyDown={handleKeyDown}
          onPaste={handlePaste}
          placeholder={placeholder}
          rows={1}
          className={cn(
            'w-full resize-none bg-transparent text-sm',
            'placeholder:text-muted-foreground/50',
            'focus:outline-none',
            'disabled:opacity-50 disabled:cursor-not-allowed',
            'min-h-[24px] max-h-[200px]'
          )}
        />
      </div>

      {/* Toolbar */}
      <div className="flex items-center justify-between">
        {/* Left side - action buttons */}
        <div className="flex items-center gap-1">
          {showFileButton && (
            <Button
              type="button"
              size="icon"
              variant="ghost"
              className="h-8 w-8 text-muted-foreground hover:text-foreground cursor-pointer"
              onClick={handleAttachmentClick}
              disabled={isBusy}
              aria-label="Attach file"
            >
              <Paperclip className="h-4 w-4" />
            </Button>
          )}
          {showImageButton && (
            <Button
              type="button"
              size="icon"
              variant="ghost"
              className="h-8 w-8 text-muted-foreground hover:text-foreground cursor-pointer"
              onClick={handleImageClick}
              disabled={isBusy}
              aria-label="Attach image"
            >
              <ImagePlus className="h-4 w-4" />
            </Button>
          )}
        </div>

        {/* Right side - send/stop button */}
        <div className="flex items-center gap-2">
          {isBusy ? (
            <Button
              type="button"
              size="icon"
              variant="default"
              onClick={stopGeneration}
              className="h-8 w-8 rounded-full cursor-pointer"
              aria-label="Stop generating"
            >
              <Square className="h-3 w-3" fill="currentColor" />
            </Button>
          ) : (
            <Button
              type="button"
              size="icon"
              onClick={handleSend}
              disabled={!canSend}
              className="h-8 w-8 rounded-full cursor-pointer"
              aria-label="Send message"
            >
              <ArrowUp className="h-4 w-4" />
            </Button>
          )}
        </div>
      </div>

        {/* Drag overlay */}
        <DragOverlay isDragging={isDragging} />
      </div>
    </div>
  );
});

ChatInput.displayName = 'ChatInput';

/**
 * ChatMessages Primitive
 *
 * A container for messages with auto-scroll behavior.
 * Uses render prop pattern for maximum flexibility.
 */

import React, { memo, useState, useLayoutEffect, type ReactNode } from 'react';
import { cn } from '@/lib/utils';
import { useAutoScroll } from '@/hooks/use-auto-scroll';
import { ChatWidthContext } from '@/hooks/use-chat-width';
import { Button } from '@/components/ui/button';
import { ArrowDown } from 'lucide-react';
import { useAgentChat } from '@inferencesh/sdk/agent';
import { type ChatMessageDTO } from '@inferencesh/sdk';

interface ChatMessagesProps {
  children: (props: { messages: ChatMessageDTO[] }) => ReactNode;
  className?: string;
  scrollToTopPadding?: boolean;
}

/**
 * ChatMessages - Scrollable message container with render prop
 *
 * @example
 * ```tsx
 * <ChatMessages>
 *   {({ messages }) => (
 *     <div className="space-y-4">
 *       {messages.map(msg => (
 *         <MessageBubble key={msg.id} message={msg}>
 *           <MessageContent message={msg} />
 *         </MessageBubble>
 *       ))}
 *     </div>
 *   )}
 * </ChatMessages>
 * ```
 *
 * @example With scroll-to-top padding (allows first message to scroll to top)
 * ```tsx
 * <ChatMessages scrollToTopPadding>
 *   {({ messages }) => <MessageList messages={messages} />}
 * </ChatMessages>
 * ```
 */
export const ChatMessages = memo(function ChatMessages({
  children,
  className,
  scrollToTopPadding = false,
}: ChatMessagesProps) {
  const { messages } = useAgentChat();
  const [spacerHeight, setSpacerHeight] = useState(0);
  const [chatWidth, setChatWidth] = useState(0);

  const {
    containerRef,
    scrollToBottom,
    handleScroll,
    shouldAutoScroll,
    handleTouchStart,
  } = useAutoScroll([messages]);

  // measure container dimensions
  useLayoutEffect(() => {
    const el = containerRef.current;
    if (!el) return;

    const update = () => {
      if (!containerRef.current) return;
      setChatWidth(containerRef.current.clientWidth);
      if (scrollToTopPadding) {
        setSpacerHeight(containerRef.current.clientHeight * 0.9);
      }
    };

    update();
    const ro = new ResizeObserver(update);
    ro.observe(el);
    return () => ro.disconnect();
  }, [scrollToTopPadding, containerRef]);

  return (
    <ChatWidthContext.Provider value={chatWidth}>
      <div className={cn('flex flex-col min-h-0 min-w-0 relative', className)}>
        <div
          ref={containerRef}
          className="flex-1 overflow-y-auto min-w-0"
          onScroll={handleScroll}
          onTouchStart={handleTouchStart}
        >
          {children({ messages })}
          {scrollToTopPadding && messages.length > 0 && (
            <div aria-hidden="true" className="shrink-0" style={{ minHeight: spacerHeight }} />
          )}
        </div>

        {/* Scroll to bottom button */}
        {!shouldAutoScroll && (
          <div className="absolute bottom-4 left-1/2 -translate-x-1/2">
            <Button
              onClick={scrollToBottom}
              size="sm"
              variant="default"
              className="bg-background hover:bg-muted text-foreground hover:text-foreground rounded-full shadow-md animate-in fade-in-0 slide-in-from-bottom-2 cursor-pointer"
            >
              <ArrowDown className="h-4 w-4" />
              <span className="text-xs font-normal text-muted-foreground">scroll to bottom</span>
            </Button>
          </div>
        )}
      </div>
    </ChatWidthContext.Provider>
  );
});

ChatMessages.displayName = 'ChatMessages';

'use client'

/**
 * VirtualizedChatMessages
 *
 * Virtualized message list with auto-scroll behavior.
 * Combines useVirtualizedList (spacers, RO height tracking, scroll correction)
 * with auto-scroll (stick to bottom on new messages, detach on scroll-up).
 */

import React, { memo, useState, useCallback, useRef, useLayoutEffect, useEffect, useMemo, type ReactNode } from 'react'
import { cn } from '@/lib/utils'
import { ChatWidthContext } from '@/hooks/use-chat-width'
import { Button } from '@/components/ui/button'
import { ArrowDown } from 'lucide-react'
import { useAgentChat } from '@inferencesh/sdk/agent'
import type { ChatMessageDTO } from '@inferencesh/sdk'
import {
  ChatMessageContentTypeText,
  ChatMessageContentTypeReasoning,
} from '@inferencesh/sdk'
import { useVirtualizedList, type VirtualItem } from '@/lib/virtualize'
import { messageStrategy } from '../lib/message-strategy'

/** Skip tool-role messages and empty messages (no text, no reasoning, no tools). */
function isRenderable(msg: ChatMessageDTO): boolean {
  if (msg.role === 'tool') return false
  const hasText = msg.content?.some(c => c.type === ChatMessageContentTypeText && c.text?.trim())
  const hasReasoning = msg.content?.some(c => c.type === ChatMessageContentTypeReasoning && c.text?.trim())
  const hasTools = msg.tool_invocations && msg.tool_invocations.length > 0
  return !!(hasText || hasReasoning || hasTools)
}

const ACTIVATION_THRESHOLD = 50
const MIN_SCROLL_UP_THRESHOLD = 10
const LIST_GAP = 8 // gap-2 between messages
const LIST_PADDING_X = 16 // px-4

interface VirtualizedChatMessagesProps {
  renderMessage: (message: ChatMessageDTO) => ReactNode
  className?: string
  scrollToTopPadding?: boolean
  /** Shown after messages when generating with no content yet */
  typingIndicator?: ReactNode
}

export const VirtualizedChatMessages = memo(function VirtualizedChatMessages({
  renderMessage,
  className,
  scrollToTopPadding = false,
  typingIndicator,
}: VirtualizedChatMessagesProps) {
  const { messages } = useAgentChat()

  // --- Container dimensions ---
  const [chatWidth, setChatWidth] = useState(0)
  const [viewportHeight, setViewportHeight] = useState(0)
  const containerElRef = useRef<HTMLDivElement | null>(null)

  // --- Auto-scroll state ---
  const [shouldAutoScroll, setShouldAutoScroll] = useState(true)
  const shouldAutoScrollRef = useRef(true)
  shouldAutoScrollRef.current = shouldAutoScroll
  const previousScrollTop = useRef<number | null>(null)

  // --- Convert renderable messages to virtual items ---
  const virtualItems: VirtualItem<ChatMessageDTO>[] = useMemo(() => {
    if (chatWidth <= 0) return []
    return messages.filter(isRenderable).map(msg => ({
      id: msg.id,
      strategy: messageStrategy(msg),
      data: msg,
    }))
  }, [messages, chatWidth])

  const list = useVirtualizedList(virtualItems, viewportHeight, chatWidth - LIST_PADDING_X * 2, LIST_GAP)

  // --- Merge scroll ref with our container ref ---
  // useVirtualizedList returns scrollRef (ref callback) that attaches scroll listener + RO.
  // We also need the element for auto-scroll + dimension measurement.
  const mergedRef = useCallback((el: HTMLDivElement | null) => {
    containerElRef.current = el
    list.scrollRef(el)
  }, [list.scrollRef])

  // --- Measure container ---
  useLayoutEffect(() => {
    const el = containerElRef.current
    if (!el) return
    const update = () => {
      if (!containerElRef.current) return
      setChatWidth(containerElRef.current.clientWidth)
      setViewportHeight(containerElRef.current.clientHeight)
    }
    update()
    const ro = new ResizeObserver(update)
    ro.observe(el)
    return () => ro.disconnect()
  }, [])

  // --- Auto-scroll: scroll handler ---
  // Only disable auto-scroll on deliberate user scroll-up.
  // Re-enable when user scrolls back to bottom.
  // Never disable from programmatic scrolls or spacer updates
  // (those look like "not at bottom" momentarily but aren't user-initiated).
  const handleScroll = useCallback(() => {
    const el = containerElRef.current
    if (!el) return

    const { scrollTop, scrollHeight, clientHeight } = el

    // Ignore Safari rubber-band
    if (scrollTop < 0 || scrollTop + clientHeight > scrollHeight + 1) return

    const distanceFromBottom = Math.abs(scrollHeight - scrollTop - clientHeight)
    const isAtBottom = distanceFromBottom < ACTIVATION_THRESHOLD

    const isScrollingUp = previousScrollTop.current !== null
      ? scrollTop < previousScrollTop.current
      : false
    const scrollUpDistance = previousScrollTop.current !== null
      ? previousScrollTop.current - scrollTop
      : 0
    const isDeliberateScrollUp = isScrollingUp && scrollUpDistance > MIN_SCROLL_UP_THRESHOLD

    if (isDeliberateScrollUp && !isAtBottom) {
      // User deliberately scrolled up — detach
      setShouldAutoScroll(false)
    } else if (isAtBottom) {
      // User scrolled back to bottom — re-attach
      setShouldAutoScroll(true)
    }
    // Otherwise: spacer update, programmatic scroll, etc. — don't change state.

    previousScrollTop.current = scrollTop
  }, [])

  const handleTouchStart = useCallback(() => {
    setShouldAutoScroll(false)
  }, [])

  const scrollToBottom = useCallback(() => {
    if (containerElRef.current) {
      containerElRef.current.scrollTop = containerElRef.current.scrollHeight
    }
  }, [])

  // --- Auto-scroll on new messages ---
  useEffect(() => {
    if (shouldAutoScrollRef.current) {
      scrollToBottom()
    }
  }, [messages, scrollToBottom])

  // --- Auto-scroll on content height growth ---
  useEffect(() => {
    const el = containerElRef.current
    if (!el) return
    let prevHeight = el.scrollHeight
    const ro = new ResizeObserver(() => {
      const h = el.scrollHeight
      if (shouldAutoScrollRef.current && h > prevHeight) {
        scrollToBottom()
      }
      prevHeight = h
    })
    ro.observe(el)
    return () => ro.disconnect()
  }, [scrollToBottom])

  // --- Spacer for scroll-to-top ---
  const spacerHeight = scrollToTopPadding ? viewportHeight * 0.9 : 0

  return (
    <ChatWidthContext.Provider value={chatWidth}>
      <div className={cn('flex flex-col min-h-0 min-w-0 relative', className)}>
        <div
          ref={mergedRef}
          className="flex-1 overflow-y-auto min-w-0"
          onScroll={handleScroll}
          onTouchStart={handleTouchStart}
        >
          {/* Top spacer (virtualizer) */}
          <div style={{ height: list.topSpacer }} />

          {/* Visible messages */}
          <div className="flex flex-col gap-2 px-4 py-3">
            {list.items.map(item => (
              <div key={item.id} ref={list.getItemRef(item.id)}>
                {renderMessage(item.data)}
              </div>
            ))}
          </div>

          {/* Bottom spacer (virtualizer) */}
          <div style={{ height: list.bottomSpacer }} />

          {/* Typing indicator — shown outside virtualizer, after all messages */}
          {typingIndicator && (
            <div className="px-4 py-2">{typingIndicator}</div>
          )}

          {/* Scroll-to-top padding */}
          {scrollToTopPadding && messages.length > 0 && (
            <div aria-hidden="true" className="shrink-0" style={{ minHeight: spacerHeight }} />
          )}
        </div>

        {/* Scroll to bottom button */}
        {!shouldAutoScroll && (
          <div className="absolute bottom-4 left-1/2 -translate-x-1/2">
            <Button
              onClick={() => {
                scrollToBottom()
                setShouldAutoScroll(true)
              }}
              size="sm"
              variant="default"
              className="bg-background hover:bg-muted text-foreground hover:text-foreground rounded-full shadow-md animate-in fade-in-0 slide-in-from-bottom-2 cursor-pointer"
            >
              <ArrowDown className="h-4 w-4" />
              <span className="text-xs font-normal text-muted-foreground">scroll to bottom</span>
            </Button>
          </div>
        )}
      </div>
    </ChatWidthContext.Provider>
  )
})

VirtualizedChatMessages.displayName = 'VirtualizedChatMessages'

/**
 * Message - Default message composition
 * 
 * Combines MessageBubble, MessageContent, MessageReasoning, and ToolInvocations
 * into a sensible default. Use individual primitives for custom layouts.
 */

import React, { memo } from 'react';
import {
  ChatMessageRoleUser,
  ChatMessageRoleAssistant,
  ChatMessageContentTypeReasoning,
  ChatMessageContentTypeText,
  ChatMessageStatusReady,
  ChatMessageStatusFailed,
  ChatMessageStatusCancelled,
  type ChatMessageDTO,
} from '@inferencesh/sdk';
import { MessageBubble } from '@/components/infsh/agent/message-bubble';
import { MessageContent } from '@/components/infsh/agent/message-content';
import { MessageReasoning } from '@/components/infsh/agent/message-reasoning';
import { ToolInvocations } from '@/components/infsh/agent/tool-invocations';

function isTerminalChatMessageStatus(status: string | undefined): boolean {
  return status === ChatMessageStatusReady ||
    status === ChatMessageStatusFailed ||
    status === ChatMessageStatusCancelled;
}

export interface MessageProps {
  message: ChatMessageDTO;
  /** Truncate user messages */
  truncateUser?: boolean;
}

/**
 * Default message rendering with all features:
 * - Reasoning block (collapsed, for assistant)
 * - Text content
 * - Tool invocations (for assistant)
 */
export const Message = memo(function Message({
  message,
  truncateUser = false,
}: MessageProps) {
  const isUser = message.role === ChatMessageRoleUser;
  const isAssistant = message.role === ChatMessageRoleAssistant;

  // Skip tool messages
  if (message.role === 'tool') return null;

  const reasoningContent = message.content?.find(
    c => c.type === ChatMessageContentTypeReasoning
  )?.text;

  const hasText = message.content?.some(
    c => c.type === ChatMessageContentTypeText && c.text?.trim()
  );

  const hasTools = message.tool_invocations && message.tool_invocations.length > 0;

  // Skip empty messages (no text, no reasoning, no tools)
  if (!hasText && !reasoningContent && !hasTools) return null;

  const isGenerating = !isTerminalChatMessageStatus(message.status);

  return (
    <MessageBubble message={message}>
      {isAssistant && reasoningContent && (
        <MessageReasoning
          reasoning={reasoningContent}
          isReasoning={isGenerating && !hasText}
        />
      )}
      <MessageContent message={message} truncate={isUser && truncateUser} />
      {isAssistant && <ToolInvocations message={message} />}
    </MessageBubble>
  );
});

/**
 * MessageBubble Primitive
 *
 * Styled container for a chat message.
 * User bubbles are shrinkwrapped to the tightest width that preserves line count.
 */

import React, { memo, type ReactNode } from 'react';
import { cn } from '@/lib/utils';
import {
  ChatMessageRoleUser,
  ChatMessageContentTypeText,
  type ChatMessageDTO,
} from '@inferencesh/sdk';
import { useChatWidth } from '@/hooks/use-chat-width';
import { useShrinkwrap } from '@/hooks/use-shrinkwrap';

const BUBBLE_MAX_RATIO = 0.7
const BUBBLE_PADDING_X = 12 // p-3
const BUBBLE_PADDING_Y = 12 // p-3 (user only, assistant has no padding)

/**
 * Returns the bubble chrome dimensions for measurement.
 * Components own their measurement — strategy just calls this.
 */
export function measureBubbleChrome(role: string, containerWidth: number): {
  innerWidth: number
  paddingY: number
} {
  const isUser = role === ChatMessageRoleUser
  if (isUser) {
    const maxBubble = Math.floor(containerWidth * BUBBLE_MAX_RATIO)
    return {
      innerWidth: maxBubble - BUBBLE_PADDING_X * 2,
      paddingY: BUBBLE_PADDING_Y * 2,
    }
  }
  return {
    innerWidth: containerWidth,
    paddingY: 0,
  }
}

function getUserText(message: ChatMessageDTO): string | undefined {
  if (message.role !== ChatMessageRoleUser) return undefined
  const parts: string[] = []
  for (const c of message.content) {
    if (c.type === ChatMessageContentTypeText && c.text) parts.push(c.text)
  }
  return parts.length > 0 ? parts.join('\n') : undefined
}

interface MessageBubbleProps {
  message: ChatMessageDTO;
  children?: ReactNode;
  className?: string;
}

/**
 * MessageBubble - Styled container for messages
 *
 * @example
 * ```tsx
 * <MessageBubble message={message}>
 *   <MessageContent message={message} />
 *   <ToolInvocations message={message} />
 * </MessageBubble>
 * ```
 */
export const MessageBubble = memo(function MessageBubble({
  message,
  children,
  className,
}: MessageBubbleProps) {
  const isUser = message.role === ChatMessageRoleUser;
  const chatWidth = useChatWidth();
  const maxBubbleWidth = Math.floor(chatWidth * BUBBLE_MAX_RATIO);
  const userText = getUserText(message);
  const shrinkWidth = useShrinkwrap(userText, maxBubbleWidth, { paddingX: BUBBLE_PADDING_X });

  return (
    <div
      className={cn(
        'group relative w-full',
        isUser ? 'flex justify-end' : 'flex justify-start',
        className
      )}
    >
      <div
        className={cn(
          'relative rounded-xl text-sm break-words [&_*]:max-w-full [&_*]:min-w-0 flex flex-col gap-1.5',
          isUser
            ? 'bg-muted/50 text-foreground max-w-[70%] min-w-0 p-3'
            : 'text-foreground max-w-full min-w-0 w-full',
        )}
        style={shrinkWidth !== undefined ? { width: shrinkWidth } : undefined}
      >
        {children}
      </div>
    </div>
  );
});

MessageBubble.displayName = 'MessageBubble';

/**
 * MessageContent Primitive
 * 
 * Renders message text content with markdown support.
 */

