/**
 * MessageContent - Renders message text with markdown
 * 
 * @example
 * ```tsx
 * <MessageContent message={message} />
 * ```
 */
export const MessageContent = memo(function MessageContent({
  message,
  className,
  truncate = false,
  renderMarkdown,
}: MessageContentProps) {
  const isUser = message.role === ChatMessageRoleUser;
  const textContent = getTextContent(message);
  const imageUrls = getImageUrls(message);
  const fileUrls = getFileUrls(message);

  const [isExpanded, setIsExpanded] = useState(false);
  const MAX_LENGTH = 500;
  const shouldTruncate = truncate && isUser && (textContent?.length || 0) > MAX_LENGTH;
  const displayContent = shouldTruncate && !isExpanded
    ? textContent?.slice(0, MAX_LENGTH) + '...'
    : textContent;

  // Don't render if no content
  if (!textContent && imageUrls.length === 0 && fileUrls.length === 0) {
    return null;
  }

  return (
    <div className={cn('w-full', className)}>
      {/* Images */}
      {imageUrls.length > 0 && (
        <div className="mb-3 flex flex-wrap gap-2">
          {imageUrls.map((url, index) => (
            <ImageAttachment key={index} url={url} />
          ))}
        </div>
      )}

      {/* Files */}
      {fileUrls.length > 0 && (
        <div className="mb-3 flex flex-wrap gap-2">
          {fileUrls.map((url, index) => (
            <FileAttachment key={index} url={url} />
          ))}
        </div>
      )}

      {/* Text content */}
      {textContent && textContent.length > 0 && (
        <div className="w-full">
          {isUser ? (
            <div className="flex flex-col gap-2">
              <div className="whitespace-pre-wrap">{displayContent}</div>
              {shouldTruncate && (
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => setIsExpanded(!isExpanded)}
                  className="self-end text-xs h-6 px-2 text-muted-foreground hover:text-foreground cursor-pointer"
                >
                  {isExpanded ? 'show less' : 'show more'}
                </Button>
              )}
            </div>
          ) : (
            renderMarkdown ? renderMarkdown(textContent) : <Markdown content={textContent} />
          )}
        </div>
      )}
    </div>
  );
});

MessageContent.displayName = 'MessageContent';

/**
 * MessageReasoning Primitive
 *
 * Collapsible block for displaying reasoning/thinking content.
 */

import React, { memo, useState } from 'react';
import { MessageCircleDashed } from 'lucide-react';
import { Spinner } from '@/components/ui/spinner';
import { CollapsibleSection } from '@/components/ui/collapsible-section';
import { Markdown } from '@/lib/pretext-md/react';

// Collapsed trigger: py-0.5 (4px) + flex row with text-xs (~16px line) + icon (12px)
// CollapsibleSection wrapper adds no extra height when closed
const TRIGGER_HEIGHT = 20

/**
 * Returns the predicted height of a reasoning block.
 * Components own their measurement — strategy just calls this.
 */
export function measureReasoning(reasoning: string | undefined, isOpen: boolean): number {
  if (!reasoning?.trim()) return 0
  if (!isOpen) return TRIGGER_HEIGHT
  // Expanded: trigger + mt-1 (4px) + border (2px) + px-2 py-1.5 (12px) + content
  // Content is capped at max-h-[200px], so worst case = 200
  return TRIGGER_HEIGHT + 4 + 2 + 12 + 200
}

interface MessageReasoningProps {
  reasoning: string;
  isReasoning?: boolean;
  className?: string;
}

/**
 * MessageReasoning - Collapsible reasoning block
 *
 * @example
 * ```tsx
 * <MessageReasoning reasoning={reasoningText} isReasoning={true} />
 * ```
 */
export const MessageReasoning = memo(function MessageReasoning({
  reasoning,
  isReasoning = false,
  className,
}: MessageReasoningProps) {
  const [isOpen, setIsOpen] = useState(false);

  if (!reasoning.trim()) return null;

  const getLastLine = () => {
    const lines = reasoning.trim().split('\n').filter((line) => line.trim().length > 0);
    for (let i = lines.length - 1; i >= 0; i--) {
      const line = lines[i].trim();
      if (line.length > 50) {
        return line.length > 60 ? line.slice(0, 60) + '...' : line;
      }
    }
    return null;
  };

  const label = isReasoning ? 'thinking' : 'thought';
  const icon = isReasoning
    ? <Spinner className="size-3" />
    : <MessageCircleDashed className="h-3 w-3" />;
  const preview =
    isReasoning && getLastLine() ? (
      <span className="text-muted-foreground/40 truncate max-w-[300px] lowercase ml-1">
        - {getLastLine()}
      </span>
    ) : null;

  return (
    <CollapsibleSection
      icon={icon}
      label={label}
      open={isOpen}
      onOpenChange={setIsOpen}
      isActive={isReasoning}
      preview={preview}
      className={className}
    >
      <div className="px-2 py-1.5">
        <div className="whitespace-pre-wrap text-xs max-h-[200px] overflow-y-auto">
          <Markdown content={reasoning} />
        </div>
      </div>
    </CollapsibleSection>
  );
});

MessageReasoning.displayName = 'MessageReasoning';

