/**
 * Message measurement strategy for virtualization.
 *
 * Pure coordinator — calls each component's measure function and sums.
 * Components own their dimensions, this just composes them.
 */

import {
  ChatMessageRoleUser,
  ChatMessageRoleAssistant,
  ChatMessageContentTypeReasoning,
  ChatMessageContentTypeText,
  type ChatMessageDTO,
} from '@inferencesh/sdk'
import { parse } from '@/lib/pretext-md/core/parser'
import { measureBlocks } from '@/lib/pretext-md/core/block-layout'
import { defaultConfig } from '@/lib/pretext-md/react/context'
import { defaultPlugins } from '@/lib/pretext-md/react/plugins'
import { measureBubbleChrome } from '@/components/infsh/agent/message-bubble'
import { measureReasoning } from '@/components/infsh/agent/message-reasoning'
import { measureToolInvocations } from '@/components/infsh/agent/tool-invocations'
import type { MeasureStrategy } from '@/lib/virtualize'

const plugins = defaultPlugins()

export function messageStrategy(message: ChatMessageDTO): MeasureStrategy {
  // Pre-parse once — AST doesn't change with width.
  // Only measureBlocks() depends on width. This avoids re-parsing on resize.
  const text = message.content?.find(
    c => c.type === ChatMessageContentTypeText
  )?.text
  const blocks = text?.trim() ? parse(text) : null

  // Pre-extract static values
  const reasoning = message.role === ChatMessageRoleAssistant
    ? message.content?.find(c => c.type === ChatMessageContentTypeReasoning)?.text
    : undefined
  const toolInvocations = message.role === ChatMessageRoleAssistant
    ? message.tool_invocations
    : undefined

  return {
    kind: 'computed',
    measure: (width) => {
      const bubble = measureBubbleChrome(message.role, width)
      let height = bubble.paddingY

      height += measureReasoning(reasoning, false)

      if (blocks) {
        const result = measureBlocks(blocks, {
          maxWidth: bubble.innerWidth,
          fonts: defaultConfig.fonts,
          lineHeights: defaultConfig.lineHeights,
          plugins,
        })
        height += result.height
      }

      height += measureToolInvocations(toolInvocations)

      return height
    },
  }
}

/**
 * useAutoScroll Hook
 * 
 * Auto-scrolls container to bottom when content changes.
 * Returns refs and handlers for scroll management.
 */

import { useCallback, useEffect, useRef, useState } from 'react';

// How many pixels from the bottom of the container to enable auto-scroll
const ACTIVATION_THRESHOLD = 50;
// Minimum pixels of scroll-up movement required to disable auto-scroll
const MIN_SCROLL_UP_THRESHOLD = 10;

export function useAutoScroll(dependencies: React.DependencyList) {
    const containerRef = useRef<HTMLDivElement | null>(null);
    const previousScrollTop = useRef<number | null>(null);
    const [shouldAutoScroll, setShouldAutoScroll] = useState(true);
    // Use a ref to track current value for ResizeObserver callback (avoids re-subscribing)
    const shouldAutoScrollRef = useRef(shouldAutoScroll);
    shouldAutoScrollRef.current = shouldAutoScroll;

    const scrollToBottom = useCallback(() => {
        if (containerRef.current) {
            containerRef.current.scrollTop = containerRef.current.scrollHeight;
        }
    }, []);

    const handleScroll = useCallback(() => {
        if (containerRef.current) {
            const { scrollTop, scrollHeight, clientHeight } = containerRef.current;

            // Detect Safari's rubber-band/bounce scrolling at edges.
            // When bouncing, scrollTop can go negative (top) or exceed max (bottom).
            // Ignore these events to avoid false "deliberate scroll up" detection.
            const isOverscrolling =
                scrollTop < 0 || scrollTop + clientHeight > scrollHeight + 1;

            if (isOverscrolling) {
                // Don't update previousScrollTop during overscroll to avoid
                // detecting the bounce-back as intentional scrolling
                return;
            }

            const distanceFromBottom = Math.abs(
                scrollHeight - scrollTop - clientHeight
            );

            const isScrollingUp = previousScrollTop.current !== null
                ? scrollTop < previousScrollTop.current
                : false;

            const scrollUpDistance = previousScrollTop.current !== null
                ? previousScrollTop.current - scrollTop
                : 0;

            const isDeliberateScrollUp =
                isScrollingUp && scrollUpDistance > MIN_SCROLL_UP_THRESHOLD;

            // Check if we're at the bottom
            const isScrolledToBottom = distanceFromBottom < ACTIVATION_THRESHOLD;

            if (isDeliberateScrollUp && !isScrolledToBottom) {
                // User deliberately scrolled up AND is not at bottom - disable auto-scroll
                setShouldAutoScroll(false);
            } else if (!isScrollingUp || isScrolledToBottom) {
                // Either scrolling down, or content changed, or at bottom
                setShouldAutoScroll(isScrolledToBottom);
            }
            // When scrolling up but not deliberately (small amounts), do nothing
            // to avoid toggling shouldAutoScroll and causing feedback loops

            previousScrollTop.current = scrollTop;
        }
    }, []);

    const handleTouchStart = useCallback(() => {
        setShouldAutoScroll(false);
    }, []);

    useEffect(() => {
        if (containerRef.current) {
            previousScrollTop.current = containerRef.current.scrollTop;
        }
    }, []);

    // Observe content height changes and auto-scroll if needed
    useEffect(() => {
        const container = containerRef.current;
        if (!container) return;

        let previousHeight = container.scrollHeight;

        const resizeObserver = new ResizeObserver(() => {
            const currentHeight = container.scrollHeight;
            // Only auto-scroll when content grows, not when it shrinks
            // (e.g., when generating indicator disappears)
            if (shouldAutoScrollRef.current && currentHeight > previousHeight) {
                scrollToBottom();
            }
            previousHeight = currentHeight;
        });

        // Observe the container itself for size changes
        resizeObserver.observe(container);

        return () => {
            resizeObserver.disconnect();
        };
    }, [scrollToBottom]);

    useEffect(() => {
        if (shouldAutoScroll) {
            scrollToBottom();
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, dependencies);

    return {
        containerRef,
        scrollToBottom,
        handleScroll,
        shouldAutoScroll,
        handleTouchStart,
    };
}

'use client'

import { useMemo } from 'react'
import { shrinkwrap } from '@/lib/pretext-md/core/shrinkwrap'
import { usePretextMdConfig } from '@/lib/pretext-md/react/context'
import type { FontConfig, LineHeightConfig } from '@/lib/pretext-md/core/types'

/**
 * Hook that returns the tightest pixel width for a markdown string
 * that preserves the same total height.
 *
 * Reads font config from PretextMdContext — wrap your app with
 * <PretextMdContext.Provider> to configure fonts for your project.
 *
 * Returns undefined when shrinkwrap isn't needed (empty, single line).
 */
export function useShrinkwrap(
  text: string | undefined,
  maxWidth: number,
  options?: {
    font?: string
    lineHeight?: number
    paddingX?: number
  },
): number | undefined {
  const config = usePretextMdConfig()
  const font = options?.font ?? config.fonts.body
  const lineHeight = options?.lineHeight ?? config.lineHeights.body
  const paddingX = options?.paddingX ?? 12

  return useMemo(() => {
    if (!text?.trim()) return undefined
    const contentWidth = maxWidth - paddingX * 2
    if (contentWidth <= 0) return undefined

    const fonts: FontConfig = {
      ...config.fonts,
      body: font,
      bold: `bold ${font}`,
      italic: `italic ${font}`,
      boldItalic: `bold italic ${font}`,
    }
    const lineHeights: LineHeightConfig = { ...config.lineHeights, body: lineHeight }

    const result = shrinkwrap(text, { maxWidth: contentWidth, fonts, lineHeights })
    if (result.width >= contentWidth) return undefined

    return result.width + paddingX * 2
  }, [text, maxWidth, paddingX, font, lineHeight, config])
}

